"use strict";(self.webpackChunkwebsite=self.webpackChunkwebsite||[]).push([["745"],{5293(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"link","href":"/docs/introduction","label":"Introduction","docId":"introduction","unlisted":false},{"type":"link","href":"/docs/quick-start","label":"Quick Start","docId":"quick-start","unlisted":false},{"type":"link","href":"/docs/directory-structure","label":"Directory Structure","docId":"directory-structure","unlisted":false},{"type":"category","label":"Core Concepts","items":[{"type":"link","href":"/docs/service-providers","label":"Service Providers","docId":"service-providers","unlisted":false},{"type":"link","href":"/docs/auto-discovery","label":"Auto-Discovery","docId":"auto-discovery","unlisted":false},{"type":"link","href":"/docs/container","label":"Container","docId":"container","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Guides","items":[{"type":"link","href":"/docs/routing","label":"Routing","docId":"routing","unlisted":false},{"type":"link","href":"/docs/models","label":"Models","docId":"models","unlisted":false},{"type":"link","href":"/docs/views","label":"Views","docId":"views","unlisted":false},{"type":"link","href":"/docs/theme","label":"Theme","docId":"theme","unlisted":false},{"type":"link","href":"/docs/context","label":"Context","docId":"context","unlisted":false},{"type":"link","href":"/docs/modules","label":"Modules","docId":"modules","unlisted":false},{"type":"link","href":"/docs/api-controllers","label":"API Controllers","docId":"api-controllers","unlisted":false},{"type":"link","href":"/docs/events","label":"Events","docId":"events","unlisted":false},{"type":"link","href":"/docs/configuration","label":"Configuration","docId":"configuration","unlisted":false},{"type":"link","href":"/docs/options","label":"Options","docId":"options","unlisted":false},{"type":"link","href":"/docs/cli-commands","label":"CLI Commands","docId":"cli-commands","unlisted":false},{"type":"link","href":"/docs/caching","label":"Caching","docId":"caching","unlisted":false},{"type":"link","href":"/docs/debugging","label":"Debugging","docId":"debugging","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Integrations","items":[{"type":"link","href":"/docs/layotter","label":"Layotter","docId":"layotter","unlisted":false},{"type":"link","href":"/docs/acf","label":"Advanced Custom Fields","docId":"acf","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Reference","items":[{"type":"link","href":"/docs/facades","label":"Facades","docId":"facades","unlisted":false},{"type":"link","href":"/docs/upgrade","label":"Upgrade Guide","docId":"upgrade","unlisted":false},{"type":"link","href":"/docs/contributing","label":"Contributing","docId":"contributing","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"link","href":"/docs/development","label":"Development","docId":"development","unlisted":false},{"type":"link","href":"/docs/polylang","label":"Polylang","docId":"polylang","unlisted":false},{"type":"link","href":"/docs/roadmap","label":"Roadmap","docId":"roadmap","unlisted":false}]},"docs":{"acf":{"id":"acf","title":"Advanced Custom Fields","description":"Sloth integrates with Advanced Custom Fields (ACF) at the model level. ACF fields are resolved automatically on model retrieval \u2014 no extra configuration needed.","sidebar":"docsSidebar"},"api-controllers":{"id":"api-controllers","title":"API Controllers","description":"Sloth can auto-discover REST API controllers from app/Api/ or theme/Api/. Drop a class extending Sloth\\\\Api\\\\Controller in either directory and Sloth registers the endpoints automatically under /wp-json/sloth/v1/.","sidebar":"docsSidebar"},"auto-discovery":{"id":"auto-discovery","title":"Auto-Discovery","description":"Sloth uses a manifest-based auto-discovery system to find your classes automatically. Drop a file in the right directory and Sloth picks it up on the next request \u2014 no registration, no configuration.","sidebar":"docsSidebar"},"caching":{"id":"caching","title":"Caching","description":"Sloth provides Laravel\'s Cache system with two drivers out of the box: file (default) and WordPress Transients.","sidebar":"docsSidebar"},"cli-commands":{"id":"cli-commands","title":"CLI Commands","description":"Sloth integrates with WP-CLI and exposes all commands under the wp sloth namespace. Commands are discovered automatically from app/Console/, theme/Console/ and the framework itself.","sidebar":"docsSidebar"},"configuration":{"id":"configuration","title":"Configuration","description":"Sloth uses Laravel\'s config system. Config files live in config/ and are loaded automatically on boot.","sidebar":"docsSidebar"},"container":{"id":"container","title":"Container","description":"Sloth\'s service container is Laravel\'s container \u2014 the same DI system that powers Laravel applications. It manages class dependencies and performs dependency injection automatically.","sidebar":"docsSidebar"},"context":{"id":"context","title":"Context","description":"The template context is the set of variables available in every Twig template. Sloth builds it lazily \u2014 values are only resolved when the template actually accesses them.","sidebar":"docsSidebar"},"contributing":{"id":"contributing","title":"Contributing","description":"Contributions to Sloth are welcome. This page covers the essentials \u2014 setup, workflow and conventions.","sidebar":"docsSidebar"},"debugging":{"id":"debugging","title":"Debugging","description":"Sloth integrates PHP DebugBar for local development. It is only active when the package is installed and WP_ENV is local.","sidebar":"docsSidebar"},"development":{"id":"development","title":"Development","description":"Running Tests","sidebar":"docsSidebar"},"directory-structure":{"id":"directory-structure","title":"Directory Structure","description":"Sloth scans two directories for classes: app/ and theme/. Which directories actually exist depends on the mode.","sidebar":"docsSidebar"},"events":{"id":"events","title":"Events","description":"Sloth provides two complementary ways to react to WordPress hooks: the declarative hook system in service providers, and the WordPress Event Bridge which connects WordPress hooks to Laravel\'s event dispatcher.","sidebar":"docsSidebar"},"facades":{"id":"facades","title":"Facades","description":"Facades provide a static interface to services bound in the container. Sloth registers all facades automatically \u2014 no configuration needed.","sidebar":"docsSidebar"},"introduction":{"id":"introduction","title":"Introduction","description":"Sloth is a polymorphic WordPress application framework. It brings Laravel patterns \u2014 Dependency Injection, Service Providers, Facades, Eloquent, Events, Cache \u2014 into WordPress, without requiring the full Laravel stack.","sidebar":"docsSidebar"},"layotter":{"id":"layotter","title":"Layotter","description":"Layotter is a WordPress page builder plugin, originally developed by Dennis Hingst at Qu\xe4ntchen + Gl\xfcck. Built before Gutenberg existed, it was an innovative approach to structured content editing \u2014 and one of the core inspirations for Sloth itself. Sloth originally grew out of Layotter and Modulator, both largely his work.","sidebar":"docsSidebar"},"models":{"id":"models","title":"Models","description":"Sloth models represent WordPress custom post types as Eloquent models. Under the hood, Sloth builds on Corcel \u2014 a Laravel package that maps WordPress database tables to Eloquent models. If you\'ve used Eloquent before, models will feel immediately familiar.","sidebar":"docsSidebar"},"modules":{"id":"modules","title":"Modules","description":"Modules are reusable UI components \u2014 a PHP class paired with a Twig template. Drop a class extending Sloth\\\\Module\\\\Module into app/Module/ or theme/Module/ and Sloth discovers it automatically.","sidebar":"docsSidebar"},"options":{"id":"options","title":"Options","description":"Sloth provides a unified API over WordPress Core get_option() and ACF Options pages. The resolution order is always: ACF option field first (if ACF is active), WordPress core option as fallback.","sidebar":"docsSidebar"},"polylang":{"id":"polylang","title":"Polylang","description":"Polylang is a WordPress multilingual plugin. Sloth detects it automatically. When the plugin is active, its translation functions are registered in Twig without any additional configuration.","sidebar":"docsSidebar"},"quick-start":{"id":"quick-start","title":"Quick Start","description":"This guide walks you through the three core building blocks of a Sloth application: a Model, a Route, and a Module. By the end you\'ll have a working page that queries data and renders it with Twig.","sidebar":"docsSidebar"},"README":{"id":"README","title":"README","description":"You can find the online version of the Laravel documentation at https://folivoro.com/docs"},"roadmap":{"id":"roadmap","title":"Roadmap","description":"This page documents planned changes, open decisions and known issues for upcoming releases. It is intentionally transparent \u2014 if you\'re building on Sloth today, this tells you what\'s coming and what to expect.","sidebar":"docsSidebar"},"routing":{"id":"routing","title":"Routing","description":"Sloth comes with two complementary routing mechanisms: the WordPress Template Hierarchy for standard content pages, and a custom router for anything that goes beyond what WordPress offers.","sidebar":"docsSidebar"},"service-providers":{"id":"service-providers","title":"Service Providers","description":"A service provider is a class that tells the application how to wire things together. It answers two questions: what exists (register) and what happens when the app boots (boot).","sidebar":"docsSidebar"},"theme":{"id":"theme","title":"Theme","description":"TODO!","sidebar":"docsSidebar"},"upgrade":{"id":"upgrade","title":"Upgrade Guide","description":"Upgrading to 2.0","sidebar":"docsSidebar"},"views":{"id":"views","title":"Views","description":"Sloth uses Twig as its templating engine. Templates live in theme/View/ and receive a rich context automatically \u2014 no manual setup needed.","sidebar":"docsSidebar"}}}}')}}]);